parameters.jsCode:
const body = $input.first().json.body || $input.first().json;
const prompt = body.prompt || body.query || body.message || '';
const system = body.system || 'You are a precise AI assistant for the Apex fintech platform. Think step by step.';
const task   = body.task   || 'general';
if (!prompt) throw new Error('Missing prompt field in request body');
return [{ json: { prompt, system, task, received_at: new Date().toISOString() } }];

const items = $input.all();
const prompt = $('Prepare Prompt').item.json.prompt;

const models = [
  { name: 'deepseek-r1', label: 'DeepSeek-R1 (Reasoning)' },
  { name: 'qwen3',       label: 'Qwen3 (Analysis)'        },
  { name: 'kimi-k2',     label: 'Kimi K2 (Thinking)'      },
];

const responses = items.map((item, i) => {
  const raw = item.json;
  const text = raw.response || raw.message?.content || raw.error || '';
  // Strip <think> tags from Kimi output for clean display
  const cleaned = text.replace(/<think>[\s\S]*?<\/think>/gi, '').trim();
  const wordCount = cleaned.split(/\s+/).length;
  const hasCode = (cleaned.match(/```/g) || []).length > 0;
  const score = wordCount * 0.5 + (hasCode ? 50 : 0) + (cleaned.length > 100 ? 30 : 0);
  return {
    model: models[i]?.name || `model_${i}`,
    label: models[i]?.label || `Model ${i}`,
    response: cleaned,
    raw_response: text,
    word_count: wordCount,
    has_code: hasCode,
    score,
    eval_count: raw.eval_count || 0,
    total_duration_ms: Math.round((raw.total_duration || 0) / 1e6),
  };
});

const best = [...responses].sort((a, b) => b.score - a.score)[0];

return [{ json: {
  prompt,
  best_model: best.model,
  best_label: best.label,
  best_response: best.response,
  all_responses: responses,
  scored_at: new Date().toISOString(),
} }];

parameters.jsonBody:
={{ JSON.stringify({
  task:    $json.prompt.substring(0, 200),
  query:   $json.prompt,
  model:   'tri-model:deepseek-r1+qwen3+kimi-k2',
  success: true,
  score:   $json.all_responses.reduce((s,r)=>s+r.score,0) / $json.all_responses.length
}) }}

parameters.responseBody:
={{ JSON.stringify({
  success: true,
  best_model: $('Score & Select Best').item.json.best_label,
  response:   $('Score & Select Best').item.json.best_response,
  all_models: $('Score & Select Best').item.json.all_responses.map(r=>({
    model: r.label, score: r.score, words: r.word_count,
    duration_ms: r.total_duration_ms
  })),
  timestamp: $('Score & Select Best').item.json.scored_at
}) }}
